            ages[i] = sc.nextInt();
        }
        // Read the edges of the main tree
        int A, B;
        char C;
        for (i = 0; i < N - 1; i++) {
            A = sc.nextInt();
            B = sc.nextInt();
            C = sc.next().charAt(0);
        }
        // Read the number of queries
        Q = sc.nextInt();
